import{_ as t,c as s,o as i,ae as a}from"./chunks/framework.CDjunVez.js";const g=JSON.parse('{"title":"PHP Settings","description":"","frontmatter":{},"headers":[],"relativePath":"website/phpsetting.md","filePath":"website/phpsetting.md"}'),o={name:"website/phpsetting.md"};function n(r,e,d,l,c,p){return i(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="php-settings" tabindex="-1">PHP Settings <a class="header-anchor" href="#php-settings" aria-label="Permalink to &quot;PHP Settings&quot;">​</a></h1><p>KiwiPanel gives you per-website control over PHP configuration. Each website can have its own PHP version, performance tuning, error handling, and <code>open_basedir</code> override — all managed from one page. Security directives like <code>disable_functions</code> are managed server-wide at <strong>Settings → PHP Security</strong>.</p><p>Navigate to <strong>Websites → (your site) → PHP</strong> to access the PHP settings page.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Changes take effect immediately after saving. KiwiPanel writes the settings to a per-vhost PHP configuration and reloads the web server — no manual restart needed.</p></div><h2 id="php-version" tabindex="-1">PHP Version <a class="header-anchor" href="#php-version" aria-label="Permalink to &quot;PHP Version&quot;">​</a></h2><p>Each website can run a different PHP version. KiwiPanel detects which versions are installed on your server and shows them in a dropdown.</p><table tabindex="0"><thead><tr><th>Version</th><th>Status</th></tr></thead><tbody><tr><td>PHP 8.4</td><td>Latest stable</td></tr><tr><td>PHP 8.3</td><td>Active support</td></tr><tr><td>PHP 8.2</td><td>Security fixes only</td></tr><tr><td>PHP 8.1</td><td>End of life</td></tr><tr><td>PHP 7.4</td><td>End of life</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Changing the PHP version restarts the PHP process for that website. Active requests will be terminated. Do this during low-traffic periods.</p></div><p><strong>To change the PHP version:</strong></p><ol><li>Open your website&#39;s PHP settings page</li><li>Select the desired version from the <strong>PHP Version</strong> dropdown</li><li>Click <strong>Save Settings</strong></li></ol><p>The page will reload and show the new version with its installed extensions.</p><hr><h2 id="settings-overview" tabindex="-1">Settings Overview <a class="header-anchor" href="#settings-overview" aria-label="Permalink to &quot;Settings Overview&quot;">​</a></h2><p>PHP settings are organized into five categories on the settings page. Each setting shows its current value, which you can modify directly.</p><h3 id="resource-limits" tabindex="-1">Resource Limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource Limits&quot;">​</a></h3><p>Control how much CPU and memory PHP can use per request.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>memory_limit</code></td><td>256M</td><td>Maximum memory a single script can consume. Increase for memory-intensive applications (e.g., WordPress with WooCommerce).</td></tr><tr><td><code>max_execution_time</code></td><td>30</td><td>Maximum seconds a script can run before being terminated. Increase for long-running tasks like imports or report generation.</td></tr><tr><td><code>max_input_time</code></td><td>60</td><td>Maximum seconds PHP will spend parsing request data (POST, GET, file uploads).</td></tr><tr><td><code>max_input_vars</code></td><td>1000</td><td>Maximum number of input variables accepted. Increase if you have forms with many fields (e.g., WooCommerce product variations).</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For WordPress with WooCommerce, recommended values are:</p><ul><li><code>memory_limit</code>: 512M</li><li><code>max_execution_time</code>: 300</li><li><code>max_input_vars</code>: 5000</li></ul></div><h3 id="file-upload" tabindex="-1">File Upload <a class="header-anchor" href="#file-upload" aria-label="Permalink to &quot;File Upload&quot;">​</a></h3><p>Control file upload sizes and limits.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>upload_max_filesize</code></td><td>64M</td><td>Maximum size of a single uploaded file. Must be ≤ <code>post_max_size</code>.</td></tr><tr><td><code>post_max_size</code></td><td>64M</td><td>Maximum size of the entire POST body (all files + form data combined). Must be ≥ <code>upload_max_filesize</code>.</td></tr><tr><td><code>max_file_uploads</code></td><td>20</td><td>Maximum number of files that can be uploaded in a single request.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>post_max_size</code> must be greater than or equal to <code>upload_max_filesize</code>. If <code>post_max_size</code> is smaller, uploads will silently fail.</p></div><h3 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h3><p>Control how PHP reports and logs errors.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>display_errors</code></td><td>Off</td><td>Whether to show errors directly on web pages. <strong>Never enable in production</strong> — error messages can leak sensitive information.</td></tr><tr><td><code>error_reporting</code></td><td><code>E_ALL &amp; ~E_DEPRECATED &amp; ~E_STRICT</code></td><td>Which types of errors to report. <code>E_ALL</code> catches everything; the default skips deprecation and strict notices.</td></tr><tr><td><code>log_errors</code></td><td>On</td><td>Whether to write errors to the website&#39;s error log file. Always keep this enabled for debugging.</td></tr></tbody></table><p><strong>Recommended for development:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>display_errors: On</span></span>
<span class="line"><span>error_reporting: E_ALL</span></span>
<span class="line"><span>log_errors: On</span></span></code></pre></div><p><strong>Recommended for production:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>display_errors: Off</span></span>
<span class="line"><span>error_reporting: E_ALL &amp; ~E_DEPRECATED &amp; ~E_STRICT</span></span>
<span class="line"><span>log_errors: On</span></span></code></pre></div><h3 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to &quot;Session&quot;">​</a></h3><p>Control PHP session behavior.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>session.gc_maxlifetime</code></td><td>1440</td><td>Seconds before session data is considered garbage and eligible for cleanup. Default is 24 minutes.</td></tr><tr><td><code>session.cookie_lifetime</code></td><td>0</td><td>Lifetime of the session cookie in seconds. <code>0</code> means the cookie expires when the browser closes.</td></tr></tbody></table><h3 id="other" tabindex="-1">Other <a class="header-anchor" href="#other" aria-label="Permalink to &quot;Other&quot;">​</a></h3><p>Additional PHP settings for timezone and caching.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>date.timezone</code></td><td>UTC</td><td>Default timezone for date/time functions. Set this to your target audience&#39;s timezone.</td></tr><tr><td><code>opcache.enable</code></td><td>1</td><td>Enable PHP&#39;s opcode cache. Significantly improves performance by caching compiled PHP scripts. <strong>Always keep enabled in production.</strong></td></tr><tr><td><code>opcache.memory_consumption</code></td><td>128</td><td>Memory allocated for opcode caching in MB. Increase for large applications with many PHP files.</td></tr></tbody></table><hr><h2 id="installed-extensions" tabindex="-1">Installed Extensions <a class="header-anchor" href="#installed-extensions" aria-label="Permalink to &quot;Installed Extensions&quot;">​</a></h2><p>The PHP settings page shows a list of extensions currently installed for your website&#39;s PHP version. Extensions are labeled as:</p><ul><li><strong>core</strong> (green badge) — Built-in extensions that are part of PHP itself (e.g., json, date, pcre). These cannot be removed.</li><li><strong>ext</strong> (blue badge) — Additional extensions installed via the system package manager (e.g., gd, intl, redis). These can be installed or removed by an administrator.</li></ul><p>The extension list is version-specific — PHP 8.3 and PHP 8.4 can have completely different extensions installed.</p><h3 id="installing-new-extensions" tabindex="-1">Installing New Extensions <a class="header-anchor" href="#installing-new-extensions" aria-label="Permalink to &quot;Installing New Extensions&quot;">​</a></h3><p>Extension management depends on your role:</p><p><strong>If you are an administrator:</strong></p><p>Go to <strong>Settings → Services</strong> to install or remove PHP extensions. Extensions are managed per PHP version — you can install <code>php8.4-redis</code> independently from <code>php8.3-redis</code>.</p><p><strong>If you are a regular user:</strong></p><p>Contact your server administrator to request extension installation. Let them know:</p><ul><li>Which extension you need (e.g., <code>gd</code>, <code>redis</code>, <code>imagick</code>)</li><li>Which PHP version it should be installed for</li></ul><h3 id="commonly-used-extensions" tabindex="-1">Commonly Used Extensions <a class="header-anchor" href="#commonly-used-extensions" aria-label="Permalink to &quot;Commonly Used Extensions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Extension</th><th>Package</th><th>Description</th></tr></thead><tbody><tr><td>GD</td><td><code>phpX.Y-gd</code></td><td>Image processing (JPEG, PNG, GIF, WebP)</td></tr><tr><td>Imagick</td><td><code>phpX.Y-imagick</code></td><td>Advanced image processing via ImageMagick</td></tr><tr><td>Intl</td><td><code>phpX.Y-intl</code></td><td>Internationalization (number/date formatting, collation)</td></tr><tr><td>mbstring</td><td><code>phpX.Y-mbstring</code></td><td>Multibyte string handling (UTF-8, CJK)</td></tr><tr><td>MySQL</td><td><code>phpX.Y-mysql</code></td><td>MySQL/MariaDB database support</td></tr><tr><td>PostgreSQL</td><td><code>phpX.Y-pgsql</code></td><td>PostgreSQL database support</td></tr><tr><td>Redis</td><td><code>phpX.Y-redis</code></td><td>Redis in-memory data store client</td></tr><tr><td>cURL</td><td><code>phpX.Y-curl</code></td><td>HTTP client for external API calls</td></tr><tr><td>Zip</td><td><code>phpX.Y-zip</code></td><td>ZIP archive creation and extraction</td></tr><tr><td>BCMath</td><td><code>phpX.Y-bcmath</code></td><td>Arbitrary precision mathematics</td></tr><tr><td>Soap</td><td><code>phpX.Y-soap</code></td><td>SOAP web services client/server</td></tr><tr><td>XML</td><td><code>phpX.Y-xml</code></td><td>XML parsing and manipulation</td></tr></tbody></table><p>Replace <code>X.Y</code> with your PHP version (e.g., <code>php8.4-redis</code>).</p><hr><h2 id="custom-directives" tabindex="-1">Custom Directives <a class="header-anchor" href="#custom-directives" aria-label="Permalink to &quot;Custom Directives&quot;">​</a></h2><p>For settings not available in the UI, you can add custom PHP directives directly. These are written as raw <code>php.ini</code> syntax and applied to your website&#39;s PHP configuration.</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">; Example custom directives</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">realpath_cache_size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 4096k</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">realpath_cache_ttl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 600</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">output_buffering</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 4096</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Invalid directives may cause PHP to fail. Test changes carefully and check the error log if your website stops working after saving.</p></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Your administrator may disable custom directives for your account. If the custom directives section is not visible, contact your administrator.</p></div><hr><h2 id="security-settings" tabindex="-1">Security Settings <a class="header-anchor" href="#security-settings" aria-label="Permalink to &quot;Security Settings&quot;">​</a></h2><p>PHP security is split into two tiers: <strong>global settings</strong> managed server-wide, and <strong>per-website overrides</strong> for <code>open_basedir</code> only. For a complete guide to PHP security layers, see <a href="./../features/phpsecurity.html">PHP Security</a>.</p><h3 id="global-security-settings-php-ini-system" tabindex="-1">Global Security Settings (PHP_INI_SYSTEM) <a class="header-anchor" href="#global-security-settings-php-ini-system" aria-label="Permalink to &quot;Global Security Settings (PHP_INI_SYSTEM)&quot;">​</a></h3><p>The following directives are <code>PHP_INI_SYSTEM</code> — they can only be set at the server level and apply to <strong>all websites</strong>. They are managed at <strong>Settings → PHP Security</strong> (<code>/settings/php-security</code>).</p><h4 id="disable-functions" tabindex="-1">disable_functions <a class="header-anchor" href="#disable-functions" aria-label="Permalink to &quot;disable_functions&quot;">​</a></h4><p>Controls which PHP functions are blocked from being called. Four presets are available:</p><table tabindex="0"><thead><tr><th>Preset</th><th>Description</th></tr></thead><tbody><tr><td><strong>Standard</strong> (default)</td><td>Blocks dangerous functions like <code>exec</code>, <code>system</code>, <code>passthru</code>, <code>shell_exec</code>, <code>proc_open</code>, <code>popen</code>. Best for most websites.</td></tr><tr><td><strong>Relaxed</strong></td><td>Allows some functions that Standard blocks. Use for applications that need controlled system access (e.g., some WordPress plugins).</td></tr><tr><td><strong>None</strong></td><td>No functions are blocked. <strong>Not recommended for production.</strong></td></tr><tr><td><strong>Custom</strong></td><td>Specify your own comma-separated list of disabled functions.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The per-website PHP page shows the active <code>disable_functions</code> preset and the resolved function list as a <strong>read-only</strong> card. To change it, click the <strong>Manage in Settings</strong> button which links to <strong>Settings → PHP Security</strong>.</p></div><h4 id="other-global-directives" tabindex="-1">Other Global Directives <a class="header-anchor" href="#other-global-directives" aria-label="Permalink to &quot;Other Global Directives&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>expose_php</code></td><td>Off</td><td>Hides <code>X-Powered-By: PHP/x.x</code> header from responses. Keep disabled to avoid leaking version information.</td></tr><tr><td><code>allow_url_include</code></td><td>Off</td><td>Blocks <code>include()</code> and <code>require()</code> from loading remote URLs. <strong>Never enable this</strong> — it&#39;s one of the most exploited PHP misconfigurations.</td></tr><tr><td><code>session.cookie_httponly</code></td><td>On</td><td>Prevents JavaScript from accessing session cookies, mitigating XSS cookie theft.</td></tr><tr><td><code>session.cookie_secure</code></td><td>On</td><td>Session cookies are only sent over HTTPS connections.</td></tr><tr><td><code>session.use_strict_mode</code></td><td>On</td><td>Rejects session IDs not generated by PHP, preventing session fixation attacks.</td></tr></tbody></table><h3 id="per-website-open-basedir" tabindex="-1">Per-Website: open_basedir <a class="header-anchor" href="#per-website-open-basedir" aria-label="Permalink to &quot;Per-Website: open_basedir&quot;">​</a></h3><p><code>open_basedir</code> is the only security directive that can be overridden per-website. It restricts which directories PHP can access on the filesystem. When enabled, PHP can only read files within the website&#39;s home directory and a few system paths (<code>/tmp</code>, etc.).</p><p><strong>To customize open_basedir for a single website:</strong></p><ol><li>Open the website&#39;s PHP settings page</li><li>Scroll to the <strong>open_basedir Settings</strong> card</li><li>Uncheck <strong>Use global open_basedir defaults</strong></li><li>Toggle the <code>open_basedir</code> switch and optionally add extra allowed paths</li><li>Click <strong>Save open_basedir Settings</strong></li></ol><p>A badge indicates when a site has a custom override active. To revert, re-check <strong>Use global open_basedir defaults</strong> and save.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>All other security directives (<code>disable_functions</code>, <code>expose_php</code>, <code>allow_url_include</code>, <code>session.*</code>) are PHP_INI_SYSTEM and cannot be overridden per-website. They are enforced server-wide via <strong>Settings → PHP Security</strong>.</p></div><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Under the hood, KiwiPanel manages PHP settings through multiple configuration layers:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│ php.ini (system-wide defaults)  │  ← Managed by the OS package</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│ mods-available/*.ini            │  ← Global security (disable_functions,</span></span>
<span class="line"><span>│                                 │    expose_php, allow_url_include, session.*)</span></span>
<span class="line"><span>│                                 │    Managed via Settings → PHP Security</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│ OLS vhost phpIniOverride        │  ← Per-site settings (memory_limit, etc.)</span></span>
<span class="line"><span>│                                 │    + per-site open_basedir override</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│ .user.ini (user overrides)      │  ← User-created (limited by PHP_INI_USER)</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span>
<span class="line"><span>         ↓ later layers override earlier ones</span></span></code></pre></div><p><strong>Important:</strong> PHP_INI_SYSTEM directives (<code>disable_functions</code>, <code>expose_php</code>, <code>allow_url_include</code>, <code>session.cookie_httponly</code>, <code>session.cookie_secure</code>, <code>session.use_strict_mode</code>) are set globally via <code>mods-available/*.ini</code> and apply to all websites. They cannot be overridden per-website because PHP enforces this restriction at the engine level.</p><p>Settings applied via <code>php_admin_value</code> in the OLS vhost config (like <code>open_basedir</code>) <strong>cannot</strong> be overridden by <code>.user.ini</code> or <code>ini_set()</code> — this is also enforced by PHP itself.</p><hr><h2 id="verifying-php-settings" tabindex="-1">Verifying PHP Settings <a class="header-anchor" href="#verifying-php-settings" aria-label="Permalink to &quot;Verifying PHP Settings&quot;">​</a></h2><p>After changing PHP settings in KiwiPanel, you can verify they are applied correctly by inspecting the live configuration from the website itself.</p><h3 id="using-the-kiwipanel-test-file" tabindex="-1">Using the KiwiPanel test file <a class="header-anchor" href="#using-the-kiwipanel-test-file" aria-label="Permalink to &quot;Using the KiwiPanel test file&quot;">​</a></h3><p>KiwiPanel includes a ready-made inspector at <code>test/manual/ini.php</code>. Copy it to your website and open it in a browser:</p><ol><li>Copy the file to your website&#39;s document root:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/kiwipanel/test/manual/ini.php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/username/public_html/ini.php</span></span></code></pre></div></li><li>Open it in your browser:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://yourdomain.com/ini.php</span></span></code></pre></div></li><li>The page displays all KiwiPanel-managed settings (resource limits, upload sizes, error handling, sessions, OPcache, security directives) along with installed extensions.</li><li>Click <strong>View Full phpinfo()</strong> for the complete PHP information output.</li></ol><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p><strong>Delete <code>ini.php</code> immediately after testing.</strong> The file exposes sensitive server configuration — PHP version, loaded extensions, file paths, and security settings — that attackers can use to target your site.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/username/public_html/ini.php</span></span></code></pre></div></div><h3 id="quick-alternative" tabindex="-1">Quick alternative <a class="header-anchor" href="#quick-alternative" aria-label="Permalink to &quot;Quick alternative&quot;">​</a></h3><p>If you just need a quick check, create a minimal file instead:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">php</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> phpinfo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>Save it as <code>info.php</code> in your <code>public_html/</code> directory, open <code>https://yourdomain.com/info.php</code>, then <strong>delete it</strong> right away.</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="changes-not-taking-effect" tabindex="-1">Changes not taking effect <a class="header-anchor" href="#changes-not-taking-effect" aria-label="Permalink to &quot;Changes not taking effect&quot;">​</a></h3><ol><li>Make sure you clicked <strong>Save Settings</strong> after making changes</li><li>Clear your application&#39;s cache (e.g., <code>wp cache flush</code> for WordPress)</li><li>Check if your application has its own PHP configuration (<code>.user.ini</code> in <code>public_html/</code>)</li><li>Wait a few seconds — OpenLiteSpeed may take a moment to reload</li></ol><h3 id="website-shows-blank-page-after-changing-settings" tabindex="-1">Website shows blank page after changing settings <a class="header-anchor" href="#website-shows-blank-page-after-changing-settings" aria-label="Permalink to &quot;Website shows blank page after changing settings&quot;">​</a></h3><ol><li>Check the error log: <strong>Websites → (your site) → Logs</strong></li><li>Common cause: <code>memory_limit</code> set too low for your application</li><li>Common cause: invalid value in custom directives</li><li>Try resetting to defaults by clicking <strong>Reset Settings</strong></li></ol><h3 id="upload-failing-silently" tabindex="-1">Upload failing silently <a class="header-anchor" href="#upload-failing-silently" aria-label="Permalink to &quot;Upload failing silently&quot;">​</a></h3><ol><li>Ensure <code>post_max_size</code> ≥ <code>upload_max_filesize</code></li><li>Check that <code>max_file_uploads</code> allows enough files</li><li>Your web server may also have its own upload limit (OpenLiteSpeed default is 2GB)</li></ol><h3 id="extensions-not-showing-up" tabindex="-1">Extensions not showing up <a class="header-anchor" href="#extensions-not-showing-up" aria-label="Permalink to &quot;Extensions not showing up&quot;">​</a></h3><ol><li>Extensions are fetched from the server in real-time. If the agent is unreachable, the extensions section won&#39;t appear.</li><li>After installing a new extension via <strong>Settings → Services</strong>, reload the PHP settings page to see it.</li><li>Different PHP versions have independent extension sets — check you&#39;re looking at the right version.</li></ol>`,100)])])}const u=t(o,[["render",n]]);export{g as __pageData,u as default};
